<template>
  <div class="base-textarea">
    <b-textarea
      v-show="!printState"
      rows="1"
      max-rows="10"
      v-model="inputValue"
      @blur="onUnFocusText"
      @change="onChange"
      :class="inputCusctomClass"
      :style="`${dynamicStyle}white-space: break-spaces;${style}`"
      :placeholder="placeholder"
    />
    <p v-show="printState"
    style="white-space: break-spaces;"
    :style="dynamicStyle"
    >
      {{ inputValue }}
    </p>
  </div>
</template>
<script>
import { mapState } from 'vuex';

export default {
  name: 'BaseTextarea',
  props: {
    value: {
      type: String,
      default: '',
    },
    placeholder: {
      type: String,
      default: null,
    },
    isSsatic: {
      type: Boolean,
      default: false,
    },
    inputCusctomClass: {
      type: String,
      default: '',
    },
  },
  data() {
    return {
      inputValue: '',
      focus: false,
    };
  },
  computed: {
    ...mapState('form', ['printState', 'currentFont']),
    style() {
      return this.isSsatic && 'overflow: hidden;';
    },
    dynamicStyle() {
      return `font-family: ${this.currentFont.style} !important;`;
    },
  },
  watch: {
    value: {
      immediate: true,
      handler: 'onUpdateValue',
    },
    inputValue: {
      immediate: true,
      handler: 'onUpdateInputValue',
    },
  },
  methods: {
    onUpdateValue() {
      if (this.inputValue) return;
      this.inputValue = this.value;
    },
    setFocusState(focus) {
      this.focus = focus;
    },
    onUpdateInputValue(inputValue) {
      this.$emit('input', inputValue);
    },
    onFocusText() {
      this.setFocusState(true);
    },
    onUnFocusText() {
      this.setFocusState(false);
      this.$emit('onFocus');
    },
    onChange() {
      this.$emit('change', this.inputValue);
    },
  },
};
</script>
<style lang="scss" scoped>
.base-textarea {
  .form-control {
    overflow: initial !important;
    border: none !important;
    box-shadow: none !important;
    &:focus {
      overflow: initial !important;
      border: none !important;
      box-shadow: none !important;
    }
    &::placeholder {
      text-align: center;
    }
    &::-webkit-scrollbar {
      display: none !important;
    }
  }
}
</style>
