<template>
  <div class="expereiance-row">
    <div class="pb-2" v-show="isFocus">
      <b-button size="sm" variant="primary" @click="addExperience"
        >add
        <b-icon icon="plus-lg" />
      </b-button>
    </div>
    <div
      v-for="(expirience, key) in expiriences[propertyName]"
      :key="`experience-key-${id}-${key}`"
    >
      <div class="container">
        <div class="row row-cols-2 justify-content-center" style="margin: 0 auto">
          <div class="text-center" style="max-width: 220px;">
            <div class="col">
              <b>
                <base-input
                  v-model="expiriences[propertyName][key].companyName"
                  classWrapper="d-flex justify-content-center"
                  @change="updateInputValue"
                  placeholder="Company name"
                  initStyle="text-align: center;"
                />
              </b>
            </div>
            <div class="col">
              <base-input
                v-model="expiriences[propertyName][key].position"
                classWrapper="d-flex justify-content-center"
                @change="updateInputValue"
                placeholder="Company position"
                initStyle="text-align: center;"
                />
            </div>
            <div class="col d-flex justify-content-center">
              <base-datepicker-range
                v-model="expiriences[propertyName][key].date"
                @context="updateInputValue"
                :isSsatic="!isFocus"
                placeholder="from"
                size="sm"
              />
            </div>
          </div>
          <div class="col position-relative">
            <base-textarea
              v-model="expiriences[propertyName][key].description"
              @change="updateInputValue"
              placeholder="Description about your expereince"
              rows="4"
            ></base-textarea>
            <b-button
              @click="deleteExpirience(key)"
              variant="outline-danger"
              size="sm"
              class="btn-delete position-absolute"
              v-show="isFocus"
              style="top: 0;right: 0px;"
            >
              <b-icon icon="trash" variant="danger" />
            </b-button>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import cloneDepp from 'lodash/cloneDeep';
import formMixin from '@/mixins/form';
import BaseTextarea from '@/components/core/BaseTextarea.vue';
import BaseInput from '@/components/core/BaseInput.vue';
import BaseDatepickerRange from '@/components/core/BaseDatepickerRange.vue';

const defaultExpereence = {
  companyName: '',
  position: '',
  date: '',
  description: '',
};

export default {
  name: 'ExpreienceInputForm',
  mixins: [formMixin],
  components: {
    BaseTextarea,
    BaseInput,
    BaseDatepickerRange,
  },
  props: {
    id: {
      type: String,
      require: true,
      default: '',
    },
    value: {
      type: Array,
      default: () => [cloneDepp(defaultExpereence)],
    },
    isFocus: {
      type: Boolean,
      default: false,
    },
  },
  data() {
    return {
      expiriences: null,
      properties: null,
      propertyName: '',
      allow: false,
    };
  },
  methods: {
    addExperience() {
      this.expiriences[this.propertyName] = [
        ...this.expiriences[this.propertyName],
        JSON.parse(JSON.stringify(defaultExpereence)),
      ];
    },
    deleteExpirience(key) {
      this.expiriences[this.propertyName] = this.expiriences[this.propertyName].filter(
        (_, index) => index !== key,
      );
    },
  },
  watch: {
    id: {
      immediate: true,
      handler() {
        this.propertyName = this.id;
        this.expiriences = { [this.propertyName]: [JSON.parse(JSON.stringify(defaultExpereence))] };
        this.properties = [`expiriences.${this.propertyName}`];
        this.updateInputValue();
      },
    },
    value: {
      immediate: true,
      handler() {
        this.expiriences[`${this.propertyName}`] = this.value;
      },
    },
    educations() {
      this.updateInputValue();
    },
  },
  mounted() {
    this.updateInputValue();
  },
};
</script>
