<!-- eslint-disable vuejs-accessibility/click-events-have-key-events -->
<template>
  <div
    class="base-datepicker-tange position-relative"
    :class="{ 'is-static': !focus }"
  >
  <div class="label-dates d-flex" :style="dynamicStyle">
    <div class="label-date-from"
    @click="togglePicker('from')">
      {{ this.config.getFormattedDate(inputValue.from) }}
    </div>
    <div class="mx-2">
      <b-icon icon="dash-lg" />
    </div>
    <div class="label-date-to"
    @click="togglePicker('to')">
      {{ this.config.getFormattedDate(inputValue.to) }}
    </div>
  </div>
  <div class="datepickers-wrapepr position-absolute"
  style="z-index: 100"
  v-if="isActiveDatePicker"
  v-click-outside="onOutsideDatePicker">
  <div class="w-100">
    <b-button-group class="w-100" :style="dynamicStyle" >
      <b-button :variant="getVariantNav('from')"
      @click="setActiveSide('from')" >З</b-button>
      <b-button :variant="getVariantNav('to')"
      @click="setActiveSide('to')" >По</b-button>
    </b-button-group>
  </div>
  <div class="d-flex">
    <div class="datepicker-from" v-if="activeSide === 'from'">
      <base-datepicker
        v-model="inputValue.from"
        :property="property"
        :inline="true"
        ref="from"
      />
    </div>
    <div class="datepicker-to" v-else>
      <base-datepicker
        v-model="inputValue.to"
        :property="property"
        :inline="true"
        ref="to"
      />
    </div>
  </div>
  </div>
  </div>
</template>
<script>
import { mapState } from 'vuex';
import BaseDatepicker from '@/components/core/BaseDatepicker.vue';
import ClickOutside from 'vue-click-outside';

export default {
  name: 'BaseDatepickerRange',
  components: {
    BaseDatepicker,
  },
  props: {
    value: {
      type: String,
      default: '',
    },
    placeholder: {
      type: String,
      default: 'Some placholder',
    },
    property: {
      type: String,
      default: 'year-month',
    },
  },
  data() {
    return {
      inputValue: {
        from: new Date(),
        to: new Date(),
      },
      focus: false,
      showDatepickerTabs: false,
      activeSide: 'from',
      isActiveDatePicker: false,
      allowOutsideClick: false,
      TIMEOUT: 100,
    };
  },
  computed: {
    ...mapState('form', ['printState', 'currentFont']),
    style() {
      return '';
    },
    activePropertyClass() {
      return this.property === 'year-month' ? 'year-month' : 'year';
    },
    dynamicStyle() {
      return `font-family: ${this.currentFont.style} !important;`;
    },
    config() {
      const variantConfig = {
        year: {
          minimumView: 'year',
          maximumView: 'year',
          format: 'yyyy',
          getFormattedDate: this.getFormatYear,
        },
        'year-month': {
          minimumView: 'month',
          maximumView: 'year',
          format: 'MM-yyyy',
          getFormattedDate: this.getFormatMonthYear,
        },
      };
      return variantConfig[this.property];
    },
  },
  watch: {
    value: {
      immediate: true,
      handler: 'onUpdateValue',
    },
    inputValue: {
      immediate: true,
      handler: 'onUpdateValue',
    },
  },
  methods: {
    onUpdateValue() {
      if (!this.value) return;
      this.inputValue = this.value;
    },
    setFocusState(focus) {
      this.focus = focus;
    },
    onUpdateInputValue(inputValue) {
      this.$emit('input', inputValue);
    },
    onFocusText() {
      this.setFocusState(true);
      this.$emit('onFocus');
    },
    onUnFocusText() {
      this.setFocusState(false);
      this.$emit('onFocus');
    },
    isActive(side) {
      return this.activeSideButton === side ? 'primary' : 'secondary';
    },
    getFormattedDate(date) {
      const getFormattedItemDate = (someDate) => (someDate < 10
        ? `0${someDate}`
        : someDate);
      const [day, month, year] = new Intl.DateTimeFormat(['ban', 'id'])
        .format(new Date(date))
        .split('/');
      return {
        day: getFormattedItemDate(day),
        month: getFormattedItemDate(month),
        year,
      };
    },
    togglePicker(side) {
      if (this.activeSide === side && this.isActiveDatePicker) {
        this.setActiveDatePicker(false);
        return;
      }
      this.setActiveSide(side);
    },
    getFormatMonthYear(date) {
      const { month, year } = this.getFormattedDate(date);
      return `${month}-${year}`;
    },
    getFormatYear(date) {
      return this.getFormattedDate(date).year;
    },
    setActiveSide(side) {
      this.allowOutsideClick = false;
      setTimeout(() => {
        this.activeSide = side;
        this.setActiveDatePicker(true);
        this.allowOutsideClick = true;
      }, this.TIMEOUT);
    },
    setActiveDatePicker(state) {
      this.isActiveDatePicker = state;
    },
    onOutsideDatePicker() {
      if (!this.allowOutsideClick) return;
      this.setActiveDatePicker(false);
    },
    getVariantNav(side) {
      return this.activeSide === side
        ? 'primary'
        : 'secondary';
    },
  },
  directives: {
    ClickOutside,
  },
};
</script>
<style lang="scss" scoped>
