  width: 165px;
  cursor: pointer;
  .datepicker-from {
    .vdp-datepicker__calendar {
      left: 4px;
    }
  }
  .datepicker-to {
    .vdp-datepicker__calendar {
      left: -12px;
    }
  }
  input.datepicker-custom.year {
    width: 40px;
  }
  input.datepicker-custom.year-month {
    width: 65px;
  }
  input {
    border: none;
    outline: none;
    &:focus {
      border: none;
      outline: none;
    }
  }
}
</style>
