<template>
  <div class="base-datepicker" :class="{ 'is-static': !focus }">
    <datepicker
      v-model="inputValue"
      :language="ru"
      :minimumView="config.minimumView"
      :maximumView="config.maximumView"
      :format="config.format"
      :inline="inline"
      :style="dynamicStyle"
      :input-class="`${currentFont.class} datepicker-custom ${activePropertyClass}`"
      :calendar-class="currentFont.class"
      @opened="onOpenCalendar()"
      @closed="onCloseCalendar"
      ref="base-datepicker"
    />
  </div>
</template>
<script>
import { mapState } from 'vuex';
import Datepicker from 'vuejs-datepicker';
// import uk from 'vuejs-datepicker/src/locale/translations/uk';
import ru from 'vuejs-datepicker/src/locale/translations/ru';

export default {
  name: 'BaseDatepicker',
  components: {
    Datepicker,
  },
  props: {
    value: {
      type: Date,
      default: '',
    },
    placeholder: {
      type: String,
      default: 'Some placholder',
    },
    property: {
      type: String,
      default: 'year-month',
    },
    inline: {
      type: Boolean,
      default: false,
    },
  },
  data() {
    return {
      inputValue: new Date(),
      focus: false,
      ru,
    };
  },
  computed: {
    ...mapState('form', ['printState', 'currentFont']),
    dynamicStyle() {
      return `font-family: ${this.currentFont.style} !important;`;
    },
    style() {
      return '';
    },
    activePropertyClass() {
      return this.property === 'year-month'
        ? 'year-month'
        : 'year';
    },
    config() {
      const variantConfig = {
        year: {
          minimumView: 'year',
          maximumView: 'year',
          format: 'yyyy',
        },
        'year-month': {
          minimumView: 'month',
          maximumView: 'year',
          format: 'MM-yyyy',
        },
      };
      return variantConfig[this.property];
    },
  },
  watch: {
    value: {
      immediate: true,
      handler: 'onUpdateValue',
    },
    inputValue: {
      immediate: true,
      handler: 'onUpdateInputValue',
    },
  },
  methods: {
    onUpdateValue() {
      if (!this.value) return;
      this.inputValue = this.value;
    },
    setFocusState(focus) {
      this.focus = focus;
    },
    onUpdateInputValue(inputValue) {
      this.$emit('input', inputValue);
    },
    onFocusText() {
      this.setFocusState(true);
      this.$emit('onFocus');
    },
    onUnFocusText() {
      this.setFocusState(false);
      this.$emit('onFocus');
    },
    onOpenCalendar() {
      this.$emit('open');
    },
    onCloseCalendar() {
      this.$emit('close');
    },
  },
};
</script>
<style lang="scss">
.base-datepicker {
  position: relative;
  input {
    cursor: pointer !important;
  }
  input.datepicker-custom.year{
    width: 40px;
    cursor: pointer !important;
  }
  input.datepicker-custom.year-month{
    width: 65;
  }
  input {
    border: none;
    outline: none;
    &:focus {
      border: none;
      outline: none;
    }
  }
}
</style>
