<template>
  <div class="expereiance-row" v-click-outside="onBlur">
    <div class="pb-2" v-show="isFocus">
      <b-button size="sm" variant="primary" @click="addExperience"
        >add
        <b-icon icon="plus-lg" />
      </b-button>
    </div>
    <div v-for="(education, key) in educations[propertyName]" :key="key">
      <div class="container">
        <div class="row row-cols-2 justify-content-center">
          <div class="text-center" style="max-width: 220px">
            <div class="col text-color-blue">
              <b>
                <base-input
                v-model="educations[propertyName][key].educationName"
                classWrapper="d-flex justify-content-center"
                 @change="updateInputValue"
                 initStyle="text-align: center;"
                 />
              </b>
            </div>
            <div class="col d-flex justify-content-center">
              <base-datepicker-range
                v-model="educations[propertyName][key].date"
                @change="updateInputValue"
                placeholder="from"
                size="sm"
              />
            </div>
          </div>
          <div class="col position-relative">
            <base-textarea
            v-model="educations[propertyName][key].description"
            placeholder="Description about your education"
             @change="updateInputValue" rows="4"
             :isSsatic="!isFocus"
             />
             <b-button
             v-show="isFocus"
               @click="deleteExpirience(key)"
               variant="outline-danger"
               size="sm"
               class="btn-delete position-absolute"
               style="top: 0px; right: 0px"
             >
               <b-icon icon="trash" variant="danger" />
             </b-button>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import cloneDepp from 'lodash/cloneDeep';
import formMixin from '@/mixins/form';
import BaseTextarea from '@/components/core/BaseTextarea.vue';
import BaseInput from '@/components/core/BaseInput.vue';
import BaseDatepickerRange from '@/components/core/BaseDatepickerRange.vue';

const defaultEducation = {
  educationName: '',
  date: '',
  description: '',
};

export default {
  name: 'EducationInputForm',
  components: {
    BaseDatepickerRange,
    BaseTextarea,
    BaseInput,
  },
  mixins: [formMixin],
  props: {
    id: {
      type: String,
      require: true,
      default: '',
    },
    value: {
      type: Array,
      default: () => [cloneDepp(defaultEducation)],
    },
    isFocus: {
      type: Boolean,
      default: false,
    },
  },
  data() {
    return {
      educations: null,
      properties: null,
      propertyName: '',
    };
  },
  methods: {
    addExperience() {
      this.educations[this.propertyName] = [
        ...this.educations[this.propertyName],
        JSON.parse(JSON.stringify(defaultEducation)),
      ];
    },
    deleteExpirience(key) {
      this.educations[this.propertyName] = this.educations[this.propertyName]?.filter(
        (_, index) => index !== key,
      );
    },
  },
  watch: {
    id: {
      immediate: true,
      handler() {
        this.propertyName = this.id;
        this.educations = { [this.propertyName]: [JSON.parse(JSON.stringify(defaultEducation))] };
        this.properties = [`educations.${this.propertyName}`];
        this.updateInputValue();
      },
    },
    value: {
      immediate: true,
      handler() {
        this.educations[`${this.propertyName}`] = this.value;
      },
    },
    educations() {
      this.updateInputValue();
    },
  },
  mounted() {
    this.updateInputValue();
  },
};
</script>

<style lang="scss">
.education-template {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  position: relative;
  .btn-delete {
    position: absolute;
    right: -40px;
    top: 0px;
  }
}
</style>
