<template>
  <div class="base-input text-center" :class="classWrapper">
    <b-input
      v-show="!printState"
      v-model="inputValue"
      @focus="onFocusText"
      @blur="onUnFocusText"
      @change="onChange"
      v-autowidth="{ maxWidth: '220px', minWidth: 'auto', comfortZone: 0 }"
      :placeholder="placeholder"
      :readonly="!focus"
      :style="`${initStyle} ${dynamicStyle}`"
    />
    <span v-show="printState"
    class="text-center"
    :style="dynamicStyle">
      {{ inputValue }}
    </span>
  </div>
</template>
<script>
import { mapState } from 'vuex';

export default {
  name: 'BaseInput',
  props: {
    value: {
      type: String,
      default: '',
    },
    initStyle: {
      type: String,
      default: '',
    },
    classWrapper: {
      type: String,
      default: '',
    },
    placeholder: {
      type: String,
      default: 'Some placholder',
    },
  },
  data() {
    return {
      inputValue: '',
      focus: false,
    };
  },
  computed: {
    ...mapState('form', ['printState', 'currentFont']),
    dynamicStyle() {
      return `font-family: ${this.currentFont.style} !important;`;
    },
  },
  watch: {
    value: {
      immediate: true,
      handler: 'onUpdateValue',
    },
    inputValue: {
      immediate: true,
      handler: 'onUpdateInputValue',
    },
  },
  methods: {
    onUpdateValue() {
      if (!this.value) return;
      this.inputValue = this.value;
    },
    setFocusState(focus) {
      this.focus = focus;
    },
    onUpdateInputValue(inputValue) {
      this.$emit('input', inputValue);
    },
    onFocusText() {
      this.setFocusState(true);
      this.$emit('onFocus');
    },
    onUnFocusText() {
      this.setFocusState(false);
      this.$emit('onFocus');
    },
    onChange() {
      this.$emit('change', this.inputValue);
    },
  },
};
</script>
<style lang="scss" scoped>
.base-input {
  .form-control {
    border: none !important;
    box-shadow: none !important;
    &:focus {
      border: none !important;
      box-shadow: none !important;
    }
  }
}
</style>
